		tL = round(inverse(totalRate));
		tU = tL;
		if (tL < 1) tL = 1; // Ensure that the minimal duration for a reaction is 1 t.u., otherwise the model will behave nondeterministically
		if (tU < 1) tU = 1;
	} else {
		tL = INFINITE_TIME;
		tU = INFINITE_TIME;
	}
	if (tL != INFINITE_TIME && tL > tU) { //We use rounded things: maybe the difference between tL and tU was not so large, and with some rounding problems we could have this case
		tL = tU;
	}
}

void react() {
	if (0 <= R + delta && R + delta <= MAX) {
		R = R + delta;
	}
}

void make_urgent() {
	c = 0;
	tU = 0;
	tL = 0;
}

bool rate_significantly_changed(double_t oldRate, double_t newRate) { //True if the new rate is at least double the old one, or if the sign of the rates is different (the reaction changes direction. Note that no change of direction will be detected if we are at MAX or 0, or we were constant until now)
	if ((oldRate.b < 0 && newRate.b > 0 || oldRate.b > 0 && newRate.b < 0) && (R < MAX && R > 0)) {
		return true;
	}
	return false;
}

void decide_reset() {
	if (rate_significantly_changed(oldRate, totalRate)) { //If the updated conditions have significantly changed the rate, restart the reaction from the beginning, without considering the work already done.
		c = 0;
	}
}

bool can_react() {
	return minCrit == N_REACTANTS && (tL != INFINITE_TIME && ((delta >= 0 && R < MAX) || (delta < 0 && R > 0)));
}

bool cant_react() {
	return minCrit == N_REACTANTS && (tL == INFINITE_TIME || (delta >= 0 && R == MAX) || (delta < 0 && R == 0));
}
